def solve(max_body_temperature, heart_rate, atrial_fibrillation, congestive_heart_failure_severity, central_nervous_system_symptoms, gastrointestinal_liver_impairment, trigger_state):
    # Step 1: Calculate the score based on the patient's maximum body temperature
    if max_body_temperature <= 37.1:
        body_temperature_score = 0
    elif 37.2 <= max_body_temperature <= 37.7:
        body_temperature_score = 5
    elif 37.8 <= max_body_temperature <= 38.2:
        body_temperature_score = 10
    elif 38.3 <= max_body_temperature <= 38.8:
        body_temperature_score = 15
    elif 38.9 <= max_body_temperature <= 39.4:
        body_temperature_score = 20
    elif 39.5 <= max_body_temperature <= 39.9:
        body_temperature_score = 25
    else:
        body_temperature_score = 30
    yield {
        "step_name": "body_temperature_score",
        "step_description": "Calculate the score based on the patient's maximum body temperature.",
        "step_result": body_temperature_score,
        "unit": None
    }

    # Step 2: Calculate the score based on the patient's heart rate
    if heart_rate < 90:
        heart_rate_score = 0
    elif 90 <= heart_rate <= 109:
        heart_rate_score = 5
    elif 110 <= heart_rate <= 119:
        heart_rate_score = 10
    elif 120 <= heart_rate <= 129:
        heart_rate_score = 15
    elif 130 <= heart_rate <= 139:
        heart_rate_score = 20
    else:
        heart_rate_score = 25
    yield {
        "step_name": "heart_rate_score",
        "step_description": "Calculate the score based on the patient's heart rate.",
        "step_result": heart_rate_score,
        "unit": None
    }

    # Step 3: Calculate the score based on the presence of atrial fibrillation
    if atrial_fibrillation == "Yes":
        atrial_fibrillation_score = 10
    else:
        atrial_fibrillation_score = 0
    yield {
        "step_name": "atrial_fibrillation_score",
        "step_description": "Calculate the score based on the presence of atrial fibrillation.",
        "step_result": atrial_fibrillation_score,
        "unit": None
    }

    # Step 4: Calculate the score based on the severity of congestive heart failure
    if congestive_heart_failure_severity == "None":
        congestive_heart_failure_score = 0
    elif congestive_heart_failure_severity == "Mild":
        congestive_heart_failure_score = 5
    elif congestive_heart_failure_severity == "Moderate":
        congestive_heart_failure_score = 10
    else:
        congestive_heart_failure_score = 15
    yield {
        "step_name": "congestive_heart_failure_score",
        "step_description": "Calculate the score based on the severity of congestive heart failure.",
        "step_result": congestive_heart_failure_score,
        "unit": None
    }

    # Step 5: Calculate the score based on the severity of central nervous system symptoms
    if central_nervous_system_symptoms == "None":
        central_nervous_system_symptoms_score = 0
    elif central_nervous_system_symptoms == "Mild":
        central_nervous_system_symptoms_score = 10
    elif central_nervous_system_symptoms == "Moderate":
        central_nervous_system_symptoms_score = 20
    else:
        central_nervous_system_symptoms_score = 30
    yield {
        "step_name": "central_nervous_system_symptoms_score",
        "step_description": "Calculate the score based on the presence and severity of central nervous system symptoms.",
        "step_result": central_nervous_system_symptoms_score,
        "unit": None
    }

    # Step 6: Calculate the score based on the severity of gastrointestinal/liver function impairment
    if gastrointestinal_liver_impairment == "None":
        gastrointestinal_liver_function_impairment_score = 0
    elif gastrointestinal_liver_impairment == "Moderate":
        gastrointestinal_liver_function_impairment_score = 10
    else:
        gastrointestinal_liver_function_impairment_score = 20
    yield {
        "step_name": "gastrointestinal_liver_function_impairment_score",
        "step_description": "Calculate the score based on the presence and severity of gastrointestinal/liver function impairment.",
        "step_result": gastrointestinal_liver_function_impairment_score,
        "unit": None
    }

    # Step 7: Calculate the score based on the presence of a clear trigger state
    if trigger_state == "No":
        trigger_state_score = 0
    else:
        trigger_state_score = 10
    yield {
        "step_name": "trigger_state_score",
        "step_description": "Calculate the score based on the presence of a clear trigger state.",
        "step_result": trigger_state_score,
        "unit": None
    }

    # Step 8: Calculate the total Burch-Wartofsky score by summing all individual scores
    total_burch_wartofsky_score = (
        body_temperature_score +
        heart_rate_score +
        atrial_fibrillation_score +
        congestive_heart_failure_score +
        central_nervous_system_symptoms_score +
        gastrointestinal_liver_function_impairment_score +
        trigger_state_score
    )
    yield {
        "step_name": "total_burch_wartofsky_score",
        "step_description": "Calculate the total Burch-Wartofsky score by summing all individual scores.",
        "step_result": total_burch_wartofsky_score,
        "unit": None
    }

    return total_burch_wartofsky_score
